exercises.solution_code:
#include <chrono>
#include <iostream>

int main()
{
    long long input{};
    std::cin >> input;

    std::chrono::microseconds us{ input };
    auto ms{ std::chrono::duration_cast<std::chrono::milliseconds>(us) };
    auto s{ std::chrono::duration_cast<std::chrono::seconds>(us) };

    std::cout << us.count() << " us" << '\n';
    std::cout << ms.count() << " ms" << '\n';
    std::cout << s.count() << " s" << '\n';

    return 0;
}

